  const tenantHomeRegion = await getTenantHomeRegion(event.tenantId);

  if (tenantHomeRegion !== process.env.AWS_REGION) {
    await forwardToRegion(event, tenantHomeRegion);
    return { statusCode: 200, body: 'Routed to home region' };
  }

  // Process in home region
