// Schema validation with tenant awareness
function validateRecord(record, tenantSchema) {
  if (record.schemaVersion !== tenantSchema.version) {
    return { valid: false, reason: 'schema_version_mismatch' };
  }

  const requiredFields = tenantSchema.fields.filter(f => f.required);
  const missingFields = requiredFields.filter(f => !(f.name in record));

  return missingFields.length === 0 
    ? { valid: true } 
    : { valid: false, reason: 'missing_fields', fields: missingFields };
}
```

