// Pseudo idempotent write: use tenantId+eventId to dedupe
async function writeEvent(tenantId, eventId, payload, region) {
  const dedupeKey = `${tenantId}/${eventId}`;
  const exists = await dynamo.getItem(dedupeKey);
  if (exists) return { status: 'duplicate', tenantId };

  await s3.putObject({
    Bucket: `tenant-${tenantId}-lake-${region}`,
    Key: `${tenantId}/${date}/${eventId}.json`,
    Body: JSON.stringify(payload),
    ServerSideEncryption: 'aws:kms',
    SSEKMSKeyId: `arn:aws:kms:${region}:.../tenant-${tenantId}-key`
  });

  await dynamo.putItem(dedupeKey, { ttl: Date.now() + 86400000 });
  return { status: 'success', tenantId };
}
```

