## Code Example
```javascript
// Pseudo rolling stats per device
const stats = {};
function handleEvent(evt){
  const id = evt.deviceId;
  if(!stats[id]) stats[id] = {sum:0, sumsq:0, n:0};
  const s = stats[id];
  s.n += 1;
  s.sum += evt.value;
  s.sumsq += evt.value * evt.value;
  const mean = s.sum / s.n;
  const varr = (s.sumsq - (s.sum*s.sum)/s.n) / (s.n-1 || 1);
  const std = Math.sqrt(varr);
  const z = (evt.value - mean) / (std || 1);
  if(Math.abs(z) > 3){ /* publish to SNS and log anomaly */ }
}
```

