## Code Example
```javascript
const crypto = require('crypto');

function redactPii(event) {
  const redactFields = ['email', 'phone', 'ssn', 'creditCard'];
  const redacted = { ...event };

  redactFields.forEach(field => {
    if (redacted[field]) redacted[field] = '[REDACTED]';
  });

  redacted.deviceId = crypto
    .createHash('sha256')
    .update(redacted.deviceId)
    .digest('hex');

  return redacted;
}
```

