import json
import jsonschema
from dataclasses import dataclass

schema = {
    "type": "object",
    "required": ["correlationId"],
    "properties": {
        "correlationId": {"type": "string"},
        "timestamp": {"type": "string", "format": "date-time"},
        "deviceId": {"type": "string"},
        "payload": {"type": "object"}
    }
}

@dataclass
class ValidationResult:
    is_valid: bool
    quality_score: float
    error_message: str = None

def validate_event(event: dict) -> ValidationResult:
    try:
        jsonschema.validate(instance=event, schema=schema)
        quality_score = compute_quality_score(event)
        return ValidationResult(is_valid=True, quality_score=quality_score)
    except jsonschema.ValidationError as e:
        return ValidationResult(is_valid=False, quality_score=0.0, error_message=str(e))

def compute_quality_score(event: dict) -> float:
    score = 1.0
    if not event.get("timestamp"):
        score -= 0.25
    if not event.get("deviceId"):
        score -= 0.25
    if not event.get("payload"):
        score -= 0.25
    return max(0.0, score)
```

