// Lambda consumer handler (Node.js)
exports.handler = async (event) => {
  const results = { processed: [], failed: [], duplicates: 0 };

  for (const record of event.Records) {
    const payload = JSON.parse(record.kinesis.data);

    // Schema validation
    if (!isValidSchema(payload)) {
      results.failed.push({ payload, error: 'INVALID_SCHEMA' });
      continue;
    }

    // Timestamp normalization
    payload.ts = normalizeTimestamp(payload.ts);

    // Deduplication check
    const dedupeKey = `${payload.deviceId}#${payload.ts}`;
    const isDuplicate = await checkAndWriteDedupe(dedupeKey);
    if (isDuplicate) {
      results.duplicates++;
      continue;
    }

    // Write to S3 Parquet
    await writeToS3Parquet(payload);
    results.processed.push(payload.deviceId);
  }

  // Handle failures - send to DLQ
  if (results.failed.length > 0) {
    await sendToDLQ(results.failed);
  }

  return results;
};

function isValidSchema(payload) {
  const required = ['deviceId', 'ts', 'sensorId', 'value'];
  return required.every(field => payload[field] !== undefined);
}

function normalizeTimestamp(ts) {
  return new Date(ts).toISOString();
}
