const { GlueSchemaRegistryClient, RegisterSchemaCommand } = require("@aws-sdk/client-glue-schema-registry");
const AWSXRay = require("aws-xray-sdk");

AWSXRay.enableAutomaticSampling();
AWSXRay.captureHTTPsGlobal(require("http"));

exports.handler = async (event) => {
  const segment = AWSXRay.getSegment();
  const subsegment = segment.addNewSubsegment("validation");

  try {
    const qualityScore = computeQualityScore(event);

    if (qualityScore < 0.5 || !validateSchema(event)) {
      await sendToDLQ(event, qualityScore);
      return { statusCode: 400, body: "Invalid record" };
    }

    await writeToS3Parquet(event, qualityScore);
    return { statusCode: 200, body: "Success" };
  } finally {
    subsegment.close();
  }
};

function computeQualityScore(record) {
  const requiredFields = ["deviceId", "tenantId", "timestamp", "payload"];
  const presentFields = requiredFields.filter(f => record[f] !== undefined);
  return presentFields.length / requiredFields.length;
}
```

