## Code Example

```python
import json
import boto3
import pandas as pd
from io import BytesIO
from datetime import datetime

MIGRATION_MAP = {
    "v1": {
        "legacy_field": "new_field",
        "old_ts": "timestamp"
    }
}
REQUIRED_FIELDS = ["event_id", "timestamp", "device_id", "payload"]

def transform_record(record):
    version = record.get("version", "vLatest")

    if version != "vLatest" and version in MIGRATION_MAP:
        for old_key, new_key in MIGRATION_MAP[version].items():
            if old_key in record:
                record[new_key] = record.pop(old_key)
        record["version"] = "vLatest"

    return record

def validate_record(record):
    return all(field in record for field in REQUIRED_FIELDS)

def write_to_s3(records):
    df = pd.DataFrame(records)
    buffer = BytesIO()
    df.to_parquet(buffer, engine="pyarrow")

    date = datetime.utcnow()
    key = f"telemetry/year={date.year}/month={date.month:02d}/day={date.day:02d}/data.parquet"

    s3 = boto3.client("s3")
    s3.put_object(Bucket="telemetry-bucket", Key=key, Body=buffer.getvalue())

def send_to_dlq(record, reason):
    sqs = boto3.client("sqs")
    sqs.send_message(
        QueueUrl="https://sqs.region.amazonaws.com/account/dlq-url",
        MessageBody=json.dumps({"record": record, "reason": reason})
    )

def handler(event, context):
    valid_records = []

    for record in event["records"]:
        payload = json.loads(record["data"])
        transformed = transform_record(payload)

        if validate_record(transformed):
            valid_records.append(transformed)
        else:
            send_to_dlq(payload, "validation_failed")

    if valid_records:
        write_to_s3(valid_records)

    return {"statusCode": 200, "body": f"Processed {len(valid_records)} records"}
```

This implementation demonstrates a clean separation of concerns: migration logic handles schema evolution, validation ensures data quality, and DLQ routing enables observability—all hallmarks of production-grade streaming pipelines.

