async function deduplicate(event, tenantId) {
  const eventId = event.id || uuid();
  const item = {
    pk: `${tenantId}#${eventId}`,
    tenantId,
    eventId,
    processedAt: Date.now(),
    ttl: Math.floor(Date.now() / 1000) + 604800 // 7 days
  };
  try {
    await docClient.put({
      TableName: 'dedupe',
      ConditionExpression: 'attribute_not_exists(pk)',
      Item: item
    }).promise();
    return true; // New event, proceed
  } catch (e) {
    if (e.code === 'ConditionalCheckFailedException') return false; // Duplicate
    throw e;
  }
}
