// Lambda validator with DLQ routing (pseudo-code)
exports.handler = async (event) => {
  const dlqPromises = [];
  const validRecords = [];

  for (const record of event.records) {
    const payload = JSON.parse(Buffer.from(record.data, 'base64').toString());

    const validation = validateTelemetry(payload);
    if (!validation.valid) {
      dlqPromises.push(sendToDLQ({ payload, error: validation.error }));
    } else {
      validRecords.push(record);
    }
  }

  await Promise.all(dlqPromises);
  return { records: validRecords.map(r => ({ recordId: r.recordId, result: 'Ok' })) };
};

function validateTelemetry(payload) {
  const required = ['deviceId', 'temperature', 'timestamp'];
  const missing = required.filter(f => !payload[f]);
  if (missing.length > 0) return { valid: false, error: `Missing fields: ${missing.join(', ')}` };
  if (typeof payload.temperature !== 'number' || payload.temperature < -50 || payload.temperature > 150) {
    return { valid: false, error: 'Temperature out of range' };
  }
  return { valid: true };
}
