// PII masking at ingest
function maskPII(record) {
  if (!record.user) return record;
  const masked = { ...record };
  if (masked.user.email) masked.user.email = masked.user.email.replace(/@.*/, "@redacted");
  if (masked.user.phone) masked.user.phone = masked.user.phone.replace(/\d{4,}$/,"****");
  return masked;
}
